import java.util.List;
import java.util.Map;

interface GenericRepository {
    Map<String, Object> find(String table, String id);
    List<Map<String, Object>> query(String sql);
    void execute(String sql);
}

UPDATE orders
   SET status = ?
 WHERE id = ?;
